Part.Source:
LoadWWPContext(&Context)
//Abre o arquivo e o transforma em variável\\ &NfeArqXML = '' &XmlReader.Open(&CaminhoArquivoXml)
Do While Not &XmlReader.EOF &NfeArqXML += &XmlReader.ReadRawXML() &XmlReader.Read() EndDo
&XmlReader.Close() //#########################################\\
//Carrega SDT da Nota\\ LeituraXmlDaNFE.Call(&NfeArqXML, &TNFeProc) //###################\\
//Nota Fiscal\\ &OpeNfeNro = Val(&TNFeProc.NFe.infNFe.ide.nNF) //Número da Nota &OpeNfeSer = &TNFeProc.NFe.infNFe.ide.serie //Série da Nota &OpeNfeChv = &TNFeProc.protNFe.infProt.chNFe //Chave da Nota &OpeNfeVlrTot = Val(&TNFeProc.NFe.infNFe.total.ICMSTot.vNF) //Valor total da Nota &OpeNfeDta = YMDTOD(Val(SubStr(&TNFeProc.NFe.infNFe.ide.dhEmi, 1, 4)), Val(SubStr(&TNFeProc.NFe.infNFe.ide.dhEmi, 6, 2)), Val(SubStr(&TNFeProc.NFe.infNFe.ide.dhEmi, 9, 2)))
For &Volume In &TNFeProc.NFe.infNFe.transp.vols &OpeNfeQtdMerEmb= Val(&Volume.pesoB) EndFor //###########\\
//Operação Capa\\ If Not &TNFeProc.NFe.infNFe.emit.CNPJ.Trim().IsEmpty() &OpeMatCNPJ = &TNFeProc.NFe.infNFe.emit.CNPJ Else &OpeMatCNPJ = &TNFeProc.NFe.infNFe.emit.CPF EndIf ValidaCpfCnpj.Call(&OpeMatCNPJ, &vFlag, &ObrigatorioCNPJ) Do 'GetContrante'
&OpeDtaIni = &Today &NfeTipFrt.FromString(&TNFeProc.NFe.infNFe.transp.modFrete)
//Contratado/Transportadora If Not &TNFeProc.NFe.infNFe.transp.transporta.CNPJ.Trim().IsEmpty() &OpeConCNPJ = &TNFeProc.NFe.infNFe.transp.transporta.CNPJ &IsContratadoJuridica = True Else &OpeConCNPJ = &TNFeProc.NFe.infNFe.transp.transporta.CPF &IsContratadoJuridica = False EndIf ValidaCpfCnpj.Call(&OpeConCNPJ, &vFlag, &ObrigatorioCNPJ) Do 'GetTransportadora' //#########################
//Destinatário If Not &TNFeProc.NFe.infNFe.dest.CNPJ.Trim().IsEmpty() &DestinatarioCPFCNPJ = &TNFeProc.NFe.infNFe.dest.CNPJ &IsDestinatarioJuridica = True Else &DestinatarioCPFCNPJ = &TNFeProc.NFe.infNFe.dest.CPF &IsDestinatarioJuridica = False EndIf ValidaCpfCnpj.Call(&DestinatarioCPFCNPJ, &vFlag, &ObrigatorioCNPJ) Do 'GetDestinatario' //############
Do Case Case &NfeTipFrt = TipoFrete.Destinatario Or &NfeTipFrt = TipoFrete.ProprioDestinatario &OpeResPgtFrt = PagamentoEfrete.Destinatario &OpeTomCod = &OpeDesCod Case &NfeTipFrt = TipoFrete.Emitente Or &NfeTipFrt = TipoFrete.ProprioEmitente &OpeResPgtFrt = PagamentoEfrete.Contratante &OpeTomCod = &OpeAntCod OtherWise &OpeResPgtFrt = PagamentoEfrete.Contratante &OpeTomCod = 0 EndCase
//#############\\
//Viagem\\
//Destino &OpeDstCidCod = Val(&TNFeProc.NFe.infNFe.dest.enderDest.cMun) &OpeDstCidCep = &TNFeProc.NFe.infNFe.dest.enderDest.CEP &OpeDstCidUfe = &TNFeProc.NFe.infNFe.dest.enderDest.UF //#######
//Origem &OpeOriCidCod = Val(&TNFeProc.NFe.infNFe.emit.enderEmit.cMun) &OpeOriCidCep = &TNFeProc.NFe.infNFe.emit.enderEmit.CEP &OpeOriCidUfe = &TNFeProc.NFe.infNFe.emit.enderEmit.UF //######
&OpeNroDoc = &TNFeProc.protNFe.infProt.nProt //######\\
For Each Order EmpCod, FilCod, OpeCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod Where OpeCod = &OpeCod
Exit When None &OpeCod = UltimoCodigoEmpresa.Udp(domParCod.OPERACAOTRANSPORTE, &Context.EmpCod, &Context.FilCod)
//CAPA DA OPERAÇÃO\\ New EmpCod = &Context.EmpCod //EMPRESA FilCod = &Context.FilCod //FILIAL OpeCod = &OpeCod //CÓDIGO DA OPERAÇÃO OpeDta = &Today //DATA DE EMISSÃO OpeTipVia = PefServiceTipoViagem.Padrao //TIPO DA VIAGEM (TIPO PADRÃO POR PADRÃO) OpeEmiGra = True //MODALIDADE DA OPERAÇÃO (TRANSFERÊNCIA BANCARIA POR PADRÃO; TRUE = Transferenciabancaria; FALSE = eFRETE) OpeMatCnpj = &OpeMatCNPJ //MATRIZ CNPJ OpeDtaIni = &Today //DATA DE INICIO DA VIAGEM (HOJE POR PADRÃO) OpeNcm = 0001 //Carga diversa por padrão OpePso = &OpeNfeQtdMerEmb //PESO REFERENTE A CARGA OpeTipEmb = PefServiceTipoEmbalagem.Indefinido //TIPO DA EMBALAGEM (INDEFINIDO POR PADRÃO) OpeConCod = &OpeConCod //CÓDIGO DO CONTRATADO (TRANSPORTADORA) OpeConCnpj = &OpeConCNPJ //CNPJ DO CONTRATADO (TRANSPORTADORA) OpeConRntrc = &OpeConRntrc //RNTRC DO CONTRATADO (TRANSPORTADORA) OpeDesCod = &OpeDesCod //CÓDIGO DO DESTINATÁRIO OpeAntCod = &OpeAntCod //CÓDIGO DO CONTRATANTE OpeResPgtFrt= &OpeResPgtFrt //RESPONSÁVEL PELO PAGAMENTO DO FRETE OpeTomCod = &OpeTomCod //CÓDIGO DO TOMADOR OpeTipCar = TipoCarga.CargaGeral //TIPO DA CARGA OpeSts = Status_CIOT.Digitando //STATUS DA OPERAÇÃO EndNew //################\\
//VIAGEM DA OPERAÇÃO\\ New EmpCod = &Context.EmpCod //EMPRESA FilCod = &Context.FilCod //FILIAL OpeCod = &OpeCod //CÓDIGO DA OPERAÇÃO OpeViaCod = 1 //CÓDIGO DA VIAGEM (1 APENAS POR SER PADRÃO) OpeDstCidCod = &OpeDstCidCod //CÓDIGO IBGE DA CIDADE DE DESTINO OpeDstCidCep = &OpeDstCidCep //CEP DA CIDADE DE DESTINO OpeDstCidUfe = &OpeDstCidUfe //UF DA CIDADE DE DESTINO OpeOriCidCod = &OpeOriCidCod //CÓDIGO IBGE DA CIDADE DE ORIGEM OpeOricidCep = &OpeOriCidCep //CEP DA CIDADE DE ORIGEM OpeOriCidUfe = &OpeOriCidUfe //UF DA CIDADE DE ORIGEM OpeNroDoc = &OpeNroDoc //DOCUMENTO REFERENTE A VIAGEM (DEVERÁ SER MAIOR QUE 10 CARACTERES) OpeTipPgt = Efrete_TipoPagamento.Transferenciabancaria //MODALIDADE DA VIAGEM (DEVERÁ SER O MESMO QUE A DA OPERAÇÃO: OpeEmiGra) OpeViaSts = Status_Autorizado.AUTORIZADO //STATUS DA VIAGEM EndNew //##################\\
//NOTAS FISCAIS\\ New EmpCod = &Context.EmpCod //EMPRESA FilCod = &Context.FilCod //FILIAL OpeCod = &OpeCod //CÓDIGO DA OPERAÇÃO OpeNfeCod = 1 //CÓDIGO DA NFE (1 PORQUE É ATRAVÉS DE UMA NFE) OpeNfeNro = &OpeNfeNro //NÚMERO DA NFE OpeNfeSer = &OpeNfeSer //SÉRIE DA NFE OpeNfeDta = &OpeNfeDta //DATA DE EMISSÃO DA NFE OpeNfeVlrTot = &OpeNfeVlrTot //VALOR TOTAL DA NFE OpeNfeNcm = 0001 //Carga diversa por padrão OpeNfeUndMed = PefServiceUnidadeDeMedidaDaMercadoria.Kg //UNIDADE DE MEDIDA DA NFE (SEMPRE EM KG) OpeNfeTipCal = PefServiceViagemTipoDeCalculo.SemQuebra //TIPO DE CALCULO OpeNfeQtdMerEmb = &OpeNfeQtdMerEmb //QUANTIDADE DE MERCADORIA EMBALADA OpeNfeTolPerTip = PefServiceTipoToleranciaDePerdaDeMercadoria.Nenhum //TOLERÂNCIA DE PESO OpeNfeChv = &OpeNfeChv //CHAVE DA NOTA EndNew //#############\\ EndFor
Commit
Sub 'GetContrante'
For Each Order EmpCod, PesCod Where EmpCod = &Context.EmpCod Where PesCnpj = &OpeMatCNPJ
&OpeAntCod = PesCod
Exit EndFor
EndSub
Sub 'GetTransportadora'
For Each Order EmpCod, PesCod Where EmpCod = &Context.EmpCod Where PesCnpj = &OpeConCNPJ When &IsContratadoJuridica = True Where PesCpf = &OpeConCNPJ When &IsContratadoJuridica = False
&OpeConCod = PesCod &OpeConRntrc = Val(PesRntrc)
Exit EndFor
EndSub
Sub 'GetDestinatario'
For Each Order EmpCod, PesCod Where EmpCod = &Context.EmpCod Where PesCnpj = &DestinatarioCPFCNPJ When &IsDestinatarioJuridica = True Where PesCpf = &DestinatarioCPFCNPJ When &IsDestinatarioJuridica = False
&OpeDesCod = PesCod
Exit EndFor
EndSub
